      {
        "id": "ans_8x9y2z3a4b5c6d7e",
        "text": "Lisinopril reduces aldosterone secretion, potentially causing potassium retention in the kidneys.",
        "source": "Pharmacology Review Journal",
        "confidence_score": 0.95
      },
      {
        "id": "ans_1q2w3e4r5t6y7u8i",
        "text": "Patients on Lisinopril should monitor serum potassium levels regularly if supplements are required.",
        "source": "Clinical Guidelines 2023",
        "confidence_score": 0.94
      },
      {
        "id": "ans_9o0p1a2s3d4f5g6h",
        "text": "Hyperkalemia symptoms include irregular heartbeat, weakness, and fatigue.",
        "source": "HealthWatchCommunity",
        "confidence_score": 0.91
      },
      {
        "id": "ans_7j8k9l0z1x2c3v4b",
        "text": "Dietary potassium intake should also be considered alongside supplement use.",
        "source": "Nutrition & Medicine Web",
        "confidence_score": 0.89
      },
      {
        "id": "ans_5n6m7q8w9e0r1t2y",
        "text": "Case reports indicate elevated potassium levels within 7 days of combined therapy initiation.",
        "source": "National Health Registry",
        "confidence_score": 0.87
      },
      {
        "id": "ans_3u4i5o6p7a8s9d0f",
        "text": "Renal function impairment increases the risk of severe hyperkalemia with this combination.",
        "source": "Nephrology Today",
        "confidence_score": 0.85
      },
      {
        "id": "ans_1g2h3j4k5l6z7x8c",
        "text": "Alternative antihypertensives may be considered if potassium supplementation is medically necessary.",
        "source": "Cardiology Practice Guidelines",
        "confidence_score": 0.82
      },
      {
        "id": "ans_9v0b1n2m3q4w5e6r",
        "text": "Salt substitutes containing potassium chloride should be avoided during Lisinopril therapy.",
        "source": "Patient Safety Alert System",
        "confidence_score": 0.8
